    ///     GET /api/v1/analytics/questions/problematic?min_responses=50
    ///     Response:
    ///     {
    ///         "too_easy": [
    ///             {
    ///                 "question_id": 15,
    ///                 "question_type": "verbal",
    ///                 "difficulty_level": "easy",
    ///                 "empirical_difficulty": 0.97,
    ///                 "discrimination": 0.15,
    ///                 "response_count": 82
    ///             }
    ///         ],
    ///         "too_hard": [],
    ///         "poor_discrimination": [...],
    ///         "negative_discrimination": []
    ///     }
    ///
    /// Use Cases:
